mapper.insert:
insert into ck(
	ck_id, ck_date, ck_winner, ck_memo, ck_created_by
) values(
 #{ckId}, #{ckDate}, #{ckWinner}, #{ckMemo}, #{ckCreatedBy}
)

insert into ck_participant(
	ck_participant_id, ck_id, ck_streamer, ck_side, ck_position
) values(
	ck_participant_seq.nextval,
	#{ckId}, #{ckStreamer}, #{ckSide}, #{ckPosition}
)

mapper.select:
select * from (
	select rownum rn, TMP.* from (
	 	select ck_id, ck_date, ck_memo from ck
	 	order by ck_date desc, ck_id desc
	) TMP
) where rn between #{begin} and #{end}

select * from (
	select rownum rn, TMP.* from (
	 	select 
	 		ck_id, ck_date, ck_memo, ck_created_by,
	 		ck_result, vs_streamer_no, vs_streamer_name
	 	 	from ck_list
	 	where ck_streamer = #{keyword}
	 	order by ck_date desc, ck_id desc
	) TMP
) where rn between #{begin} and #{end}

    select * from (
        select TMP.*,  rownum rn
        from (
            select ck.ck_id, ck.ck_date, ck.ck_memo, 
            	count(*) over() as total_count
            	from ck
            	where ck.ck_created_by = #{keyword}
            	order by ck_date desc, ck_id desc
        ) TMP
	) where rn between #{begin} and #{end}
